      "keystrokes": "python3 matched_filtering.py --data /root/data/PyCBC_T2_2.gwf --channel H1:TEST-STRAIN --approximants SEOBNRv4_opt IMRPhenomD TaylorT4 --mass-range 10 40 --mass-step 1 --output /root/detection_results.csv\n",
